create table addresses (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, address_type enum ('HOME','OTHER','WORK'), city varchar(255) not null, country varchar(255) not null, full_name varchar(255), is_default bit, landmark varchar(255), phone_number varchar(255), state varchar(255) not null, street varchar(255) not null, zip_code varchar(255) not null, user_id bigint not null, primary key (id)) engine=InnoDB;
create table banner (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, display_order integer, image_url varchar(255) not null, link varchar(255), title varchar(255), primary key (id)) engine=InnoDB;
create table brand (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, description varchar(1000), logo varchar(500), name varchar(255) not null, partnership_badge varchar(255), partnership_level enum ('EXCLUSIVE','FEATURED','NONE','PARTNER','TOP'), partnership_priority integer, primary key (id)) engine=InnoDB;
create table brand_partnership (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, contract_terms longtext, end_date date, monthly_fee decimal(10,2) not null, special_benefits longtext, start_date date not null, status enum ('ACTIVE','CANCELLED','EXPIRED','PENDING'), brand_id bigint not null, partnership_type_id bigint not null, primary key (id)) engine=InnoDB;
create table brand_partnership_type (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, badge_color varchar(255) not null, benefits longtext, description longtext, display_name varchar(255) not null, monthly_fee decimal(10,2), name varchar(255) not null, priority_boost integer, primary key (id)) engine=InnoDB;
create table cart_items (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, price decimal(38,2) not null, quantity integer not null, cart_id bigint not null, variant_id bigint not null, primary key (id)) engine=InnoDB;
create table carts (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, total_discount decimal(38,2), total_items integer, total_mrp decimal(38,2), total_selling_price decimal(38,2), user_id bigint, primary key (id)) engine=InnoDB;
create table category (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, description varchar(500), name varchar(100) not null, status varchar(255), parent_id bigint, primary key (id)) engine=InnoDB;
create table delivery_partner (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, status enum ('EXPIRED','FAILED','PENDING','VERIFIED'), user_id bigint, primary key (id)) engine=InnoDB;
create table delivery_partner_document (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, document_type varchar(255), document_url varchar(255), profile_id bigint, primary key (id)) engine=InnoDB;
create table delivery_partner_profile (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, full_name varchar(255), vehicle_number varchar(255), vehicle_type varchar(255), delivery_partner_id bigint, primary key (id)) engine=InnoDB;
create table home_page_item (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, description varchar(255), display_order integer, image_url varchar(255), link varchar(255), title varchar(255), product_id bigint, section_id bigint not null, primary key (id)) engine=InnoDB;
create table home_page_section (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, display_order integer, section_type enum ('BANNER','CATEGORY','DEALS','POPULAR','RECOMMENDED','TRENDING') not null, title varchar(255) not null, primary key (id)) engine=InnoDB;
create table notification (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, is_read bit not null, message varchar(1000), redirect_url varchar(255), reference_id bigint, reference_type enum ('OFFER','ORDER','PRODUCT','SYSTEM','USER'), title varchar(255), type enum ('LOW_STOCK','NEW_ORDER_FOR_SELLER','NEW_PRODUCT','OFFER','ORDER_CANCELLED','ORDER_CONFIRMED','ORDER_DELIVERED','ORDER_PLACED','ORDER_READY_TO_SHIP','ORDER_SHIPPED','PRICE_DROP','SYSTEM'), user_id bigint not null, primary key (id)) engine=InnoDB;
create table order_items (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, discount decimal(10,2), product_name varchar(255), product_price_snapshot decimal(10,2), quantity integer not null, stock_restored bit, total_price decimal(10,2) not null, unit_price decimal(10,2) not null, variant_name varchar(255), product_id bigint not null, shipment_id bigint not null, variant_id bigint, primary key (id)) engine=InnoDB;
create table order_status_history (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, changed_by varchar(255), new_status enum ('CANCELLED','CONFIRMED','CREATED','DELIVERED','PARTIALLY_CANCELLED','PARTIALLY_CONFIRMED','SHIPPED'), old_status enum ('CANCELLED','CONFIRMED','CREATED','DELIVERED','PARTIALLY_CANCELLED','PARTIALLY_CONFIRMED','SHIPPED'), order_id bigint, user_id bigint, primary key (id)) engine=InnoDB;
create table order_tracking (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, location varchar(255), remarks varchar(255), status varchar(255) not null, timestamp datetime(6) not null, order_id bigint not null, primary key (id)) engine=InnoDB;
create table order_item_attributes (order_item_id bigint not null, attributes varchar(255), attributes_key varchar(255) not null, primary key (order_item_id, attributes_key)) engine=InnoDB;
create table orders (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, currency varchar(255), delivery_address varchar(255) not null, delivery_date datetime(6), order_date datetime(6), order_number varchar(255) not null, status enum ('CANCELLED','CONFIRMED','CREATED','DELIVERED','PARTIALLY_CANCELLED','PARTIALLY_CONFIRMED','SHIPPED'), subtotal decimal(38,2), total_discount decimal(38,2), total_price decimal(38,2) not null, total_shipping decimal(38,2), address_id bigint, user_id bigint not null, primary key (id)) engine=InnoDB;
create table payment_attempts (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, attempted_at datetime(6), failure_reason varchar(255), gateway_order_id varchar(255), gateway_payment_id varchar(255), status enum ('CREATED','FAILED','SUCCESS'), payment_id bigint not null, primary key (id)) engine=InnoDB;
create table payments (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, amount decimal(19,2), currency varchar(255), failure_reason varchar(255), gateway varchar(255), gateway_order_id varchar(255), gateway_payment_id varchar(255), gateway_signature varchar(255), paid_amount decimal(19,2), paid_at datetime(6), payment_method enum ('CASH_ON_DELIVERY','CREDIT_CARD','DEBIT_CARD','NET_BANKING','ONLINE','UPI','WALLET'), refunded_amount decimal(19,2), refunded_at datetime(6), status enum ('CANCELLED','COLLECTED','CREATED','FAILED','PARTIALLY_PAID','PARTIALLY_REFUNDED','PENDING','REFUNDED','SUCCESS'), order_id bigint not null, primary key (id)) engine=InnoDB;
