create table product_attributes (product_id bigint not null, attribute_value varchar(255), attribute_key varchar(255) not null, primary key (product_id, attribute_key)) engine=InnoDB;
create table product_images (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, alt_text varchar(255), image_url varchar(255) not null, image_order integer, product_id bigint not null, primary key (id)) engine=InnoDB;
create table product_variants (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, price decimal(38,2), sku varchar(255), stock_quantity integer, variant_name varchar(255), product_id bigint not null, primary key (id)) engine=InnoDB;
