create table reviews (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, comment varchar(1000), rating float(53) not null, product_id bigint, seller_account_id bigint, user_id bigint not null, primary key (id)) engine=InnoDB;
