create table seller_account (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, flat_shipping_charge decimal(38,2), free_shipping bit, free_shipping_above decimal(38,2), name varchar(255) not null, status enum ('DEACTIVATED','PENDING_VERIFICATION','SUSPENDED','VERIFIED') not null, warehouse_pincode varchar(255), user_id bigint not null, primary key (id)) engine=InnoDB;
