create table shipment_tracking (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, location varchar(255), remarks varchar(255), status enum ('ACCEPTED','CREATED','DELIVERED','IN_TRANSIT','OUT_FOR_DELIVERY','READY_TO_SHIP','REJECTED','SHIPPED'), timestamp datetime(6), shipment_id bigint not null, primary key (id)) engine=InnoDB;
create table shipments (id bigint not null auto_increment, active bit not null, created_at datetime(6) not null, tenant_id bigint not null, updated_at datetime(6) not null, version bigint not null, courier_partner varchar(255), delivered_at datetime(6), discount decimal(38,2), estimated_delivery datetime(6), final_amount decimal(38,2), items_total decimal(38,2), seller_name varchar(255), seller_pincode varchar(255), shipped_at datetime(6), shipping_charge decimal(38,2), status enum ('ACCEPTED','CREATED','DELIVERED','IN_TRANSIT','OUT_FOR_DELIVERY','READY_TO_SHIP','REJECTED','SHIPPED'), tracking_id varchar(255), order_id bigint not null, seller_account_id bigint not null, primary key (id)) engine=InnoDB;
